// Persist seen offer IDs across executions — avoids re-notifying the same offer
const staticData = $getWorkflowStaticData('global');
if (!staticData.seenOffers) staticData.seenOffers = [];

// Apify sync endpoint returns a JSON array in a single item
const input = $input.first().json;
const offers = Array.isArray(input) ? input : $input.all().map(i => i.json);

const newItems = [];
for (const offer of offers) {
  const id = offer.url || offer.key;
  if (id && !staticData.seenOffers.includes(id)) {
    staticData.seenOffers.push(id);
    newItems.push({ json: offer });
  }
}

// Cap history to prevent unbounded memory growth
if (staticData.seenOffers.length > 500) {
  staticData.seenOffers = staticData.seenOffers.slice(-500);
}

return newItems;

const fs = require('fs');

let cvContent;
try {
  cvContent = fs.readFileSync('/data/cv/cv.txt', 'utf-8').trim();
} catch (err) {
  throw new Error(`Cannot read CV file: ${err.message}`);
}

return $input.all().map(item => {
  const title = item.json.title || 'Untitled';
  const link = item.json.url || '';
  const creator = item.json.employer?.name || '';
  const city = item.json.location?.city || '';

  const rawDesc = item.json.description?.text || '';
  // Truncate to avoid exceeding the model context window (4096 tokens)
  const description = rawDesc.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 1000);

  const prompt = [
    'Score the following job offer against the candidate CV.',
    'Return ONLY a valid JSON object with these exact keys:',
    '  score (integer 1-10)',
    '  match_reasons (array of strings)',
    '  concerns (array of strings)',
    '  summary (string, max 2 sentences)',
    '',
    'CV:',
    cvContent,
    '',
    'Job offer:',
    `Title: ${title}`,
    city ? `Location: ${city}` : '',
    `Description: ${description || 'N/A'}`,
  ].filter(Boolean).join('\n');

  return {
    json: {
      title,
      link,
      creator,
      body: {
        model: $env.OLLAMA_MODEL || 'mistral',
        prompt,
        stream: false,
        keep_alive: -1,
        num_predict: 512,
        // Forces the model to output valid JSON — eliminates all parsing issues
        format: 'json',
      },
    },
  };
});

return $input.all().map((item, index) => {
  const raw = item.json.response || '';

  // Retrieve original offer data from the paired upstream item
  const original = $('Prepare Request').all()[index].json;

  const openIdx = raw.indexOf('{');
  if (openIdx === -1) {
    throw new Error(`LLM scoring failed for "${original.title}": no JSON in response`);
  }

  let parsed;
  try {
    parsed = JSON.parse(raw.slice(openIdx));
  } catch (err) {
    throw new Error(`LLM scoring failed for "${original.title}": ${err.message}`);
  }

  return {
    json: {
      title: original.title,
      link: original.link,
      creator: original.creator,
      score: Number(parsed.score),
      matchReasons: Array.isArray(parsed.match_reasons) ? parsed.match_reasons : [],
      concerns: Array.isArray(parsed.concerns) ? parsed.concerns : [],
      summary: parsed.summary || '',
      chatId: $env.TELEGRAM_CHAT_ID || '',
    },
  };
});
